using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();

// Breaking change 1 — ValidateScopes is now enabled in Development (.NET 9).
// A singleton factory must not call GetRequiredService<IUserService>() on the
// root provider, because IUserService is registered as Scoped.
// Fix: create an explicit scope inside the factory.
builder.Services.AddSingleton<ICacheService>(sp =>
{
    using var scope = sp.CreateScope();
    return new CacheService(scope.ServiceProvider.GetRequiredService<IUserService>());
});

// Breaking change 2 — The default primary handler is now SocketsHttpHandler (.NET 9).
// ConfigureHttpMessageHandlerBuilder is obsolete, and the cast to HttpClientHandler
// throws InvalidCastException at runtime.
// Fix: use the new UseSocketsHttpHandler API.
builder.Services.AddHttpClient("api")
    .UseSocketsHttpHandler((handler, _) =>
    {
        handler.UseCookies = false;
    });

// Breaking change 3 — HttpClientFactory now redacts ALL header values by default (.NET 9).
// Trace-level logging shows "*" instead of real values.
// Fix: opt in to showing non-sensitive headers.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h => h.StartsWith("Authorization", StringComparison.OrdinalIgnoreCase)));

builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

